import java.sql.*;   // Import necessary Java SQL classes and interfaces here, e.g., DriverManager for loading drivers etc... .   
public class java_44415_JDBCQueryHandler_A03 {    
        public static void main(String[] args) throws Exception{        
            String url = "jdbc:mysql://localhost/testdb";       //Database URL          if needed replace with actual database connection details.  Example : jdbc:mariadb://username@password:@hostname_or_IPAddress:/databaseName?useSSL=false (For MariaDB, MySQL etc.)
            String username = "root";        // Database Username   Replace this by your specific DB user name in real environment.  Example : root or 'your-dbuser' for MySql and so on...    .         
             String password =  "";      //Database Password replace it with actual database connection details (Example: ''or @passwd$%^)   Replace this by your specific DB user name in real environment.  Example : root or 'your-dbuser' for MySql and so on...    .         
             Class.forName("com.mysql.cj.jdbc.Driver"); //Load the MySQL driver using JDBC      Here we are assuming that our database is running a MariaDb server, which has better security features compared to other databases like 'MySQL' or others (Example : com.mysql.jdbc., etc.)
             Connection conn = DriverManager.getConnection(url , username  , password ); //Create connection with the Database    Here we are assuming that our database is running a MariaDb server, which has better security features compared to other databases like 'MySQL' or others (Example : com.mysql.jdbc., etc.)
             Statement stmt = conn .createStatement();//Use statement for executing queries     e.g.: SELECT * FROM users; Here we are just selecting all rows from the "users" table in our DB database  , which is a SQL command that retrieves data (selects) form one or more tables/relations of an entire Database, and returns it as set result sets
             String sql = "SELECT passwordHash FROM Users WHERE username=?"; //Here we are getting hashed user's pass by its name. In real environment this will be a complex SQL command with multiple joins etc.. Example: SELECT PASSWORD(password) HASH  from USERS where USERNAME = 
             PreparedStatement pstmt = conn .prepareStatement (sql);//Prepare the statement using query string and parameters   e.g.: "SELECT passwordHash FROM Users WHERE username=?"    Here we are just getting hashed user's pass by its name in our DB database  , which is a SQL command that retrieves data from one or more tables/relations of an entire Database,
             pstmt .setString (1,"TestUser"); // Set parameter and get the result set. e.g.: "SELECT passwordHash FROM Users WHERE username=?" Here we are just setting 'testuser' as our user name in db database  , which is a SQL command that retrieves data from one or more tables/relations of an entire Database,
             ResultSet rs = pstmt .executeQuery (); // Execute the prepared statement and get result set. e.g.: SELECT passwordHash FROM Users WHERE username=? Here we are just executing our previous query in db database  , which is a SQL command that retrieves data from one or more tables/relations of an entire Database,
             while(rs .next()) { //Iterate through the Result Set and print each row's information. e.g.: While loop to iterating over result set rows   Replace with your own logic if needed  , which is a SQL command that retrieves data from one or more tables/relations of an entire Database,
             System .out .println (rs .getString ("passwordHash")); // Print password hash Here we are just getting each row's information about user and print it out. e.g.: While loop to iterating over result set rows   Replace with your own logic if needed  , which is a SQL command that retrieves data from one or more tables/relations of an entire Database,
             }//End while(rs .next())            //Closing the ResultSet and connection here. e.g.: closing statement object after use; endif condition checking for further iterations etc.. Replace with your own logic if needed  , which is a SQL command that retrieves data from one or more tables/relations of an entire Database,
             conn .close (); //Close the Connection and Statement here   e.g.: closing connection object after use; endif condition checking for further iterations etc.. Replace with your own logic if needed  , which is a SQL command that retrieves data from one or more tables/relations of an entire Database,
        }//End main method       //Closing the JDBC Connection here   e.g.: closing connection object after use; endif condition checking for further iterations etc.. Replace with your own logic if needed  , which is a SQL command that retrieves data from one or more tables/relations of an entire Database,
}//End class definition       //Closing the JDBC Class here   e.g.: closing jdbc object after use; endif condition checking for further iterations etc.. Replace with your own logic if needed  , which is a SQL command that retrieves data from one or more tables/relations of an entire Database,